    fn inc(date: &str, rev: f64, eps: f64) -> IncomeStatement {
        IncomeStatement {
            date: date.to_string(),
            period: "Q".to_string(),
            revenue: rev,
            eps,
            ..Default::default()
        }
    }

    fn surp(date: &str, actual: f64, est: f64) -> EarningsSurprise {
        let s = actual - est;
        EarningsSurprise {
            date: date.to_string(),
            symbol: "X".into(),
            eps_actual: actual,
            eps_estimate: est,
            surprise: s,
            surprise_pct: if est.abs() > 0.0 { s / est.abs() * 100.0 } else { 0.0 },
        }
    }

