    fn make_bar(date: &str, close: f64, volume: f64) -> HistoricalPriceRow {
        HistoricalPriceRow {
            date: date.to_string(),
            open: close,
            high: close * 1.01,
            low: close * 0.99,
            close,
            adj_close: close,
            volume,
            change: 0.0,
            change_pct: 0.0,
        }
    }

    fn make_bar_flat(date: &str, close: f64, volume: f64) -> HistoricalPriceRow {
        HistoricalPriceRow {
            date: date.to_string(),
            open: close,
            high: close,
            low: close,
            close,
            adj_close: close,
            volume,
            change: 0.0,
            change_pct: 0.0,
        }
    }

