    fn mk_financials_with_revenue(_sym: &str, revs: &[f64]) -> FinancialStatements {
        let income_annual: Vec<IncomeStatement> = revs
            .iter()
            .enumerate()
            .map(|(i, r)| IncomeStatement {
                date: format!("202{}-12-31", 6 - i),
                period: "FY".into(),
                revenue: *r,
                ..Default::default()
            })
            .collect();
        FinancialStatements {
            income_annual,
            ..Default::default()
        }
    }

